class FileManagementSystem {
private:
	std::unordered_map<std::string, int> files; // filename -> size

public:
	void createFile(const std::string &fileName, int size) {
		if (files.find(fileName) != files.end()) {
			std::cout << "Error: File '" << fileName << "' already exists.\n";
			return;
		}
		files[fileName] = size;
		std::cout << "File '" << fileName << "' created with size: " << size << "\n";
	}

	void deleteFile(const std::string &fileName) {
		if (files.find(fileName) == files.end()) {
			std::cout << "Error: File '" << fileName << "' not found.\n";
			return;
		}
		files.erase(fileName);
		std::cout << "File '" << fileName << "' deleted.\n";
	}

	void listFiles() {
		if (files.empty()) {
			std::cout << "No files available.\n";
			return;
		}
		std::cout << "Files:\n";
		for (const auto &file : files) {
			std::cout << "\t- " << file.first << ", Size: " << file.second << "\n";
		}
	}
};

