fn string_compression(input: &str) -> String {
  let mut compressed = String::new();
  let mut count = 1;

  for i in 1..input.len() {
    if input.as_bytes()[i] == input.as_bytes()[i - 1] {
      count += 1;
    } else {
      compressed.push(input.as_bytes()[i - 1] as char);
      compressed.push_str(&count.to_string());
      count = 1;
    }
  }

  compressed.push(input.as_bytes()[input.len() - 1] as char);
  compressed.push_str(&count.to_string());

  if compressed.len() < input.len() {
    compressed
  } else {
    input.to_string()
  }
}
