package main

import (
  "errors"
  "fmt"
  "math/rand"
  "net/url"
  "time"
)

type URLShortener struct {
  originalURL string
  shortURL    string
  urlMap      map[string]string
}

func NewURLShortener() *URLShortener {
  rand.Seed(time.Now().UnixNano())
  return &URLShortener{
    urlMap: make(map[string]string),
  }
}

func (us *URLShortener) StoreURL(originalURL string) (string, error) {
  // Validate URL
  _, err := url.ParseRequestURI(originalURL)
  if err != nil {
    return "", errors.New("invalid URL")
  }

  // Generate short URL
  shortURL := fmt.Sprintf("short%v", rand.Intn(10000))
  us.urlMap[shortURL] = originalURL
  return shortURL, nil
}

func (us *URLShortener) RetrieveURL(shortURL string) (string, error) {
  originalURL, exists := us.urlMap[shortURL]
  if !exists {
    return "", errors.New("short URL not found")
  }
  return originalURL, nil
}

func main() {
  shortener := NewURLShortener()
  shortURL, err := shortener.StoreURL("http://example.com")
  if err != nil {
    fmt.Println("Error storing URL:", err)
  } else {
    originalURL, err := shortener.RetrieveURL(shortURL)
    if err != nil {
      fmt.Println("Error retrieving URL:", err)
    } else {
      fmt.Printf("Short URL: %s - Original URL: %s\n", shortURL, originalURL)
    }
  }
}
