pub mod config_loader {
  use std::collections::HashMap;
  use std::fs::File;
  use std::io::{self,BufRead,BufReader};
  use std::path::Path;

  /// Loads configuration settings from a file.
  /// Returns a Result with a hashmap of key-value pairs or an error.
  pub fn load_configuration(file_path:&str) -> Result<HashMap<String,String>,Box<dyn std::error::Error>> {
    let path = Path::new(file_path);
    if !path.exists() {
      return Err(Box::new(io::Error::new(io::ErrorKind::NotFound,"File not found")));
    }

    let file = File::open(path)?;
    let reader = BufReader::new(file);

    let mut config_map = HashMap::new();
    for line in reader.lines() {
      let line = line?;
      let parts:Vec<&str> = line.splitn(2,'=').collect();
      if parts.len()!=2 {
        return Err(Box::new(io::Error::new(io::ErrorKind::InvalidData,"Invalid configuration format")));
      }
      config_map.insert(parts[0].trim().to_string(),parts[1].trim().to_string());
    }
    Ok(config_map)
  }
}
